export type Cell = [number, number];

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKey = (x: number, y: number) => `${x},${y}`;
  const liveSet = new Set(liveCells.map(([x, y]) => liveKey(x, y)));

  const candidates = new Set<string>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        candidates.add(liveKey(x + dx, y + dy));
      }
    }
  }

  const next: Cell[] = [];
  for (const key of candidates) {
    const [xs, ys] = key.split(",");
    const x = Number(xs);
    const y = Number(ys);
    let neighbors = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveSet.has(liveKey(x + dx, y + dy))) neighbors++;
      }
    }
    const alive = liveSet.has(key);
    if (alive && (neighbors === 2 || neighbors === 3)) next.push([x, y]);
    else if (!alive && neighbors === 3) next.push([x, y]);
  }
  return next;
}

